import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StatusBar, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_TOKEN_KEY = '@mvp_auth_token';
const AUTH_USER_KEY = '@mvp_auth_user';

const AuthContext = createContext(null);

async function persistAuth(token, user) {
  await AsyncStorage.multiSet([
    [AUTH_TOKEN_KEY, token],
    [AUTH_USER_KEY, JSON.stringify(user)],
  ]);
}

async function clearAuthStorage() {
  await AsyncStorage.multiRemove([AUTH_TOKEN_KEY, AUTH_USER_KEY]);
}

async function loadAuthStorage() {
  const [[, token], [, userJson]] = await AsyncStorage.multiGet([AUTH_TOKEN_KEY, AUTH_USER_KEY]);
  if (!token || !userJson) return null;
  try {
    const user = JSON.parse(userJson);
    return { token, user };
  } catch {
    return null;
  }
}

export function AuthProvider({ children }) {
  const [loading, setLoading] = useState(true);
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const stored = await loadAuthStorage();
        if (mounted && stored) {
          setToken(stored.token);
          setUser(stored.user);
        }
      } finally {
        if (mounted) setLoading(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const signIn = async ({ email, password }) => {
    const res = await fakeLoginApi(email, password);
    if (!res?.token || !res?.user) throw new Error('Authentication failed');
    setToken(res.token);
    setUser(res.user);
    await persistAuth(res.token, res.user);
  };

  const signOut = async () => {
    setToken(null);
    setUser(null);
    await clearAuthStorage();
  };

  const updateUser = async (nextUser) => {
    setUser(nextUser);
    if (token) {
      await AsyncStorage.setItem(AUTH_USER_KEY, JSON.stringify(nextUser));
    }
  };

  const value = useMemo(
    () => ({
      loading,
      isAuthenticated: !!token,
      token,
      user,
      signIn,
      signOut,
      updateUser,
    }),
    [loading, token, user]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

async function fakeLoginApi(email, password) {
  await new Promise((resolve) => setTimeout(resolve, 900));
  if (!email || !password) {
    throw new Error('Email and password are required');
  }
  if (password.length < 4) {
    throw new Error('Invalid credentials');
  }
  return {
    token: `token_${Date.now()}_${Math.random().toString(36).slice(2)}`,
    user: {
      id: 'user_1',
      name: email.split('@')[0] || 'User',
      email,
    },
  };
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('1234');
  const [submitting, setSubmitting] = useState(false);

  const onLogin = async () => {
    try {
      setSubmitting(true);
      await signIn({ email: email.trim(), password });
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Please try again');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" />
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <TextInput
          value={email}
          onChangeText={setEmail}
          placeholder="Email"
          autoCapitalize="none"
          keyboardType="email-address"
          style={styles.input}
          editable={!submitting}
        />
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Password"
          secureTextEntry
          style={styles.input}
          editable={!submitting}
        />
        <Button title={submitting ? 'Signing in...' : 'Login'} onPress={onLogin} disabled={submitting} />
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar barStyle="dark-content" />
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>Name: {user?.name}</Text>
        <Text style={styles.text}>Email: {user?.email}</Text>
        <View style={styles.spacer} />
        <Button title="Logout" onPress={signOut} />
      </View>
    </SafeAreaView>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

function AuthGate() {
  const { loading, isAuthenticated } = useAuth();

  if (loading) {
    return (
      <SafeAreaView style={styles.loadingContainer}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

